/** Native row projection stays lazy internally and materializes when crossing the Sail result boundary. */
public class LmdbNativeLazyProjectedResultTest {

	private static final String EX = "http://example.com/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI predicate = vf.createIRI(EX, "value");
			for (int i = 0; i < 64; i++) {
				connection.add(vf.createIRI(EX, "s" + i), predicate,
						vf.createLiteral("stored literal payload " + i));
			}
		}
		NativeProjectedBindingSet.CREATED.set(0);
		NativeProjectedBindingSet.MATERIALIZED_VALUES.set(0);
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	@Test
	public void sailBoundaryMaterializesAndDetachesProjectedRows() {
		BindingSet first;
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult rows = connection.prepareTupleQuery(
						"SELECT ?s ?value WHERE { ?s <" + EX + "value> ?value }").evaluate()) {
			int count = 0;
			first = null;
			while (rows.hasNext()) {
				BindingSet row = rows.next();
				if (first == null) {
					first = row;
				}
				count++;
			}
			assertThat(count).isEqualTo(64);
		}

		assertThat(NativeProjectedBindingSet.CREATED.get()).isEqualTo(64);
		assertThat(NativeProjectedBindingSet.MATERIALIZED_VALUES.get()).isEqualTo(128);
		assert first instanceof NativeProjectedBindingSet;
		assertThat(((NativeProjectedBindingSet) first).source).isNull();

		assertThat(first.getValue("value").stringValue()).startsWith("stored literal payload ");
		assertThat(NativeProjectedBindingSet.MATERIALIZED_VALUES.get()).isEqualTo(128);
		assertThat(first.getValue("value")).isSameAs(first.getValue("value"));
		assertThat(NativeProjectedBindingSet.MATERIALIZED_VALUES.get()).isEqualTo(128);
	}

	@Test
	public void projectedRowRetainsPrimitiveIdBeforeBoundaryDetach() {
		Value expected = repository.getValueFactory().createLiteral("lazy value");
		NativeLmdbQuerySource source = new StubSource(expected);
		NativeProjectedBindingSet row = new NativeProjectedBindingSet(source, new String[] { "value" },
				new int[] { 0 }, new long[] { 42L });

		assertThat(row.getBindingNames()).containsExactly("value");
		assertThat(NativeProjectedBindingSet.MATERIALIZED_VALUES.get()).isZero();
		assertThat(row.getValue("value")).isSameAs(expected);
		assertThat(NativeProjectedBindingSet.MATERIALIZED_VALUES.get()).isEqualTo(1);

		row.materializeAndDetach();
		assertThat(row.source).isNull();
		assertThat(row.getValue("value")).isSameAs(expected);
		assertThat(NativeProjectedBindingSet.MATERIALIZED_VALUES.get()).isEqualTo(1);
	}

	private static final class StubSource implements NativeLmdbQuerySource {
		private final Value value;

		private StubSource(Value value) {
			this.value = value;
		}

		@Override
		public long idOf(Value value) {
			throw new UnsupportedOperationException();
		}

		@Override
		public Value lazyValue(long id) {
			return value;
		}

		@Override
		public Object idSpace() {
			return this;
		}

		@Override
		public RecordIterator statements(long subj, long pred, long obj, long context) throws IOException {
			throw new UnsupportedOperationException();
		}

		@Override
		public long count(long subj, long pred, long obj, long context) {
			return 0L;
		}

		@Override
		public boolean has(long subj, long pred, long obj, long context) {
			return false;
		}

		@Override
		public double estimate(long subj, long pred, long obj, long context) {
			return 0D;
		}

		@Override
		public boolean hasStatementsInSource() {
			return false;
		}
	}
}
